CREATE TRIGGER [dbo].[InventoryItemAttribute_History]ON [dbo].[InventoryItemAttribute]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.InventoryItemAttributeId IS NOT NULL AND d.InventoryItemAttributeId IS NULL THEN 'I' 		WHEN i.InventoryItemAttributeId IS NOT NULL AND d.InventoryItemAttributeId IS NOT NULL THEN 'U' 		WHEN i.InventoryItemAttributeId IS NULL AND d.InventoryItemAttributeId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.InventoryItemAttributeId = d.InventoryItemAttributeId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_InventoryItemAttribute([InventoryItemAttributeId], [InventoryItemId], [ItemAttributeTypeId], [AttributeValue], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [InventoryItemAttributeId], [InventoryItemId], [ItemAttributeTypeId], [AttributeValue], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_InventoryItemAttribute([InventoryItemAttributeId], [InventoryItemId], [ItemAttributeTypeId], [AttributeValue], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [InventoryItemAttributeId], [InventoryItemId], [ItemAttributeTypeId], [AttributeValue], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND